import { useState, useEffect, useRef, useCallback } from 'react';

export const useResizable = (initialWidth: number, minWidth: number, maxWidth: number) => {
    const [width, setWidth] = useState(initialWidth);
    const [isResizing, setIsResizing] = useState(false);
    const sidebarRef = useRef<HTMLDivElement>(null);

    const startResizing = useCallback(() => setIsResizing(true), []);
    const stopResizing = useCallback(() => setIsResizing(false), []);

    useEffect(() => {
        const resize = (e: MouseEvent) => {
            if (isResizing && sidebarRef.current) {
                const newWidth = Math.max(minWidth, Math.min(e.clientX, maxWidth));
                // Direct DOM manipulation for performance during drag, avoiding React render cycle lag
                sidebarRef.current.style.width = `${newWidth}px`;
            }
        };

        const onMouseUp = () => {
            if (isResizing && sidebarRef.current) {
                // Sync final state
                const finalWidth = parseInt(sidebarRef.current.style.width, 10);
                if (!isNaN(finalWidth)) setWidth(finalWidth);
                stopResizing();
                document.body.style.cursor = '';
                document.body.style.userSelect = '';
            }
        };

        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', onMouseUp);
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none';
        }

        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', onMouseUp);
        };
    }, [isResizing, minWidth, maxWidth, stopResizing]);

    return { width, setWidth, isResizing, sidebarRef, startResizing };
};

import { useState, useRef, useCallback } from 'react';

export const useVoiceInput = (language: 'en' | 'vi', onResult: (text: string) => void) => {
    const [isListening, setIsListening] = useState(false);
    const recognitionRef = useRef<any>(null);

    const toggleListening = useCallback(() => {
        if (isListening) {
            recognitionRef.current?.stop();
            setIsListening(false);
            return;
        }

        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("Voice-to-Text is not supported in this browser.");
            return;
        }

        try {
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            recognition.lang = language === 'vi' ? 'vi-VN' : 'en-US';

            recognition.onresult = (event: any) => {
                let finalTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) {
                        finalTranscript += event.results[i][0].transcript;
                    }
                }
                if (finalTranscript) {
                    onResult(finalTranscript.trim());
                }
            };

            recognition.onerror = (event: any) => {
                console.error("Speech Error", event.error);
                setIsListening(false);
            };

            recognition.onend = () => setIsListening(false);

            recognition.start();
            recognitionRef.current = recognition;
            setIsListening(true);
        } catch (e) {
            console.error("Failed to start recognition", e);
            setIsListening(false);
        }
    }, [isListening, language, onResult]);

    return { isListening, toggleListening };
};

