                        isSidebarOpen={isSidebarOpen}
                        sidebarWidth={sidebarWidth}
                    />
                </div>
                <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                    <button onClick={() => toggleModal('recall', true)} className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all border ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600' : 'bg-white dark:bg-slate-800 text-slate-500'}`}>
                        <div className="relative">
                            <Icon name="History" size={18}/>
                            {lastSavedTime && <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5"><span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span></span>}
                        </div>
                        <span className="hidden xl:inline text-xs font-bold">Recall</span>
                    </button>
                    <button onClick={() => { if(confirm("Start New Session?")) { createManualBackup(); resetSession(); showToast("Session Reset."); }}} className="h-10 px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 border border-amber-200 rounded-xl flex items-center justify-center gap-2 hover:bg-amber-100 transition-all">
                        <Icon name="Session4_FilePlus" size={18}/>
                        <span className="hidden md:inline text-xs font-bold">New</span>
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                {showProcessBlocker && (
                    <div className="absolute inset-0 z-50 bg-white/80 dark:bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl border border-indigo-100 dark:border-indigo-900 max-w-md text-center">
                            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/50 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600"><Icon name="Session11_GridAdd" size={32} /></div>
                            <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Process Required</h3>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 leading-relaxed">Define at least one <strong>Process</strong> to begin evidence collection.</p>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setLayoutMode('planning')} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg transition-transform active:scale-95">Go to Planning</button>
                            </div>
                        </div>
                    </div>
                )}

                {layoutMode === 'planning' && <PlanningView />}

                {layoutMode === 'evidence' && (
                    <EvidenceView
                        evidence={evidence} setEvidence={setEvidence}
                        uploadedFiles={uploadedFiles} setUploadedFiles={setUploadedFiles}
                        onOcrProcess={() => {}} isOcrLoading={false}
                        onAnalyze={() => {}} isReadyForAnalysis={false} isAnalyzeLoading={false} analyzeTooltip="AI Analysis"
                        onExport={() => {}} evidenceLanguage='en' setEvidenceLanguage={() => {}}
                        textareaRef={{ current: null }} tags={evidenceTags} onAddTag={addEvidenceTag}
                        selectedClauses={selectedClauses} standards={standards} standardKey={standardKey}
                        matrixData={matrixData} setMatrixData={setMatrixData}
                    />
                )}

                {layoutMode === 'findings' && (
                    <FindingsView
                        analysisResult={analysisResult} setAnalysisResult={setAnalysisResult}
                        selectedFindings={selectedFindings} setSelectedFindings={setSelectedFindings}
                        isAnalyzeLoading={false} loadingMessage="" currentAnalyzingClause=""
                        viewMode="list" setViewMode={() => {}} focusedFindingIndex={0} setFocusedFindingIndex={() => {}}
                        onExport={() => {}} notesLanguage="en" setNotesLanguage={() => {}}
                    />
                )}

                {layoutMode === 'report' && (
                    <ReportView
                        finalReportText={finalReportText} setFinalReportText={setFinalReportText}
                        isReportLoading={false} loadingMessage="" templateFileName=""
                        handleTemplateUpload={() => {}} handleGenerateReport={() => {}}
                        isReadyToSynthesize={false} onExport={() => {}} exportLanguage="en" setExportLanguage={() => {}}
                    />
                )}
            </div>

            {/* Modals */}
            <SettingsModal 
                isOpen={modals.settings} onClose={() => toggleModal('settings', false)} 
                apiKeys={apiKeys} newKeyInput="" setNewKeyInput={() => {}} isCheckingKey={isCheckingKey}
                handleAddKey={() => { const i = document.querySelector('input[type="password"]') as HTMLInputElement; if(i) addKey(i.value); }} 
                activeKeyId={activeKeyId} editingKeyId={null} editLabelInput="" setEditLabelInput={() => {}}
                handleSaveLabel={() => {}} handleStartEdit={() => {}} handleRefreshStatus={refreshKeyStatus} handleDeleteKey={deleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled} toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={modals.addStandard} onClose={() => toggleModal('addStandard', false)}
                onAdd={async (name, file) => {
                    toggleModal('addStandard', false);
                    const newKey = `CUSTOM_${Date.now()}`;
                    if(file) { const text = await processSourceFile(file); setKnowledgeData(text, file.name); }
                    addCustomStandard(newKey, { name, description: "Custom", groups: [] });
                    setStandardKey(newKey);
                }}
            />

            <ReferenceClauseModal
                isOpen={referenceState.isOpen} onClose={() => setReferenceState(prev => ({...prev, isOpen: false}))}
                clause={referenceState.clause} standardName={standards[standardKey]?.name || ""}
                fullText={referenceState.fullText} isLoading={referenceState.isLoading}
                onInsert={(text) => setEvidence(prev => prev + "\n" + text)}
            />
        </MainLayout>
    );
};

export default function App() {
    return (
        <UIProvider>
            <KeyPoolProvider>
                <AuditProvider>
                    <AppContent />
                </AuditProvider>
            </KeyPoolProvider>
        </UIProvider>
    );
}

import React, { useRef, useState } from 'react';
import { Icon, IconSelect, IconInput } from '../UI';
import { StandardsData, AuditInfo, AuditProcess } from '../../types';
import { AUDIT_TYPES } from '../../constants';
import { useUI } from '../../contexts/UIContext';

interface AuditInfoFormProps {
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    onAddNewStandard: () => void;
    onOpenIntegrity: () => void;
    knowledgeFileName: string | null;
    onKnowledgeUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onClearKnowledge: () => void;
    health: { isHealthy: boolean; score: number };
    auditFieldIconColor: string;
    standardOptions: { value: string; label: string }[];

    scopes: AuditProcess[];
    activeScopeId: string | null;
    onAddScope: (name: string) => void;
    onChangeScope: (id: string) => void;
    onRenameScope: (id: string, name: string) => void;
    onDeleteScope: (id: string) => void;
}

export const AuditInfoForm: React.FC<AuditInfoFormProps> = ({
    standards, standardKey, setStandardKey, auditInfo, setAuditInfo,
    onAddNewStandard, onOpenIntegrity,
    knowledgeFileName, onKnowledgeUpload, onClearKnowledge, health, auditFieldIconColor, standardOptions,
    scopes: processes, activeScopeId: activeProcessId, onAddScope: addProcess, onChangeScope: changeProcess, onRenameScope: renameProcess, onDeleteScope: deleteProcess
}) => {
    const { showToast } = useUI();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const processInputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLDivElement>(null); // Auto-scroll ref
    const skipBlurRef = useRef(false);

    const [inputValue, setInputValue] = useState(""); 
    const [editingProcessId, setEditingProcessId] = useState<string | null>(null);
    const [editName, setEditName] = useState("");
    const [isProcessMenuOpen, setIsProcessMenuOpen] = useState(false);
    const [isCreating, setIsCreating] = useState(false);

    // Logic icon
    const hasSource = !!knowledgeFileName;
    const isStandardSelected = !!standardKey && standardKey !== "ADD_NEW";
    const sourceIcon = hasSource ? "BookOpen" : "Book";

    let sourceColor = "text-gray-300 dark:text-slate-600"; 
    let sourceTooltip = "Please select an ISO Standard first to enable document upload.";
    let cursorClass = "cursor-not-allowed";

    if (hasSource) {
        sourceColor = "text-emerald-500 drop-shadow-sm";
        sourceTooltip = `Source Attached: ${knowledgeFileName}. Click to Replace.`;
        cursorClass = "cursor-pointer";
    } else if (isStandardSelected) {
        sourceColor = `${auditFieldIconColor} hover:text-indigo-600 dark:hover:text-indigo-300`;
        sourceTooltip = "Click to upload Source PDF or Word (DOCX) for better accuracy";
        cursorClass = "cursor-pointer hover:scale-110 active:scale-95";
    }

    const handleIconClick = () => {
        if (!isStandardSelected) return;
        if (fileInputRef.current) fileInputRef.current.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onKnowledgeUpload(e);
            e.target.value = '';
        }
    };

    // --- INPUT HANDLER ---
    const handleAddKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            const trimmed = inputValue.trim();
            if (trimmed) {
                const existing = processes.find(s => s.name.toLowerCase() === trimmed.toLowerCase());
                if (existing) {
                    changeProcess(existing.id);
                    showToast(`Switched to: ${existing.name}`);
                    setIsCreating(false); 
                    setInputValue("");
                    setIsProcessMenuOpen(false); // Close if selecting existing
                } else {
                    skipBlurRef.current = true;
                    addProcess(trimmed);
                    setInputValue(""); 

                    // Keep UX active
                    setIsCreating(true); 
                    setIsProcessMenuOpen(true); // KEEP LIST OPEN to show added item

                    // Auto-scroll to bottom to show new item
                    setTimeout(() => {
                        if (listRef.current) {
                            listRef.current.scrollTop = listRef.current.scrollHeight;
                        }
                        if (processInputRef.current) {
                            processInputRef.current.focus();
                        }
                        skipBlurRef.current = false;
                    }, 50);
                }
            } else {
                setIsCreating(false);
            }
        } else if (e.key === 'Escape') {
            setIsCreating(false);
            setInputValue("");
        }
    };

    const handleInputBlur = () => {
        if (skipBlurRef.current) return;
        if (!inputValue.trim()) {
            setIsCreating(false);
        }
    };

    // --- SMART DELETE HANDLER ---
    const handleDeleteClick = (e: React.MouseEvent, id: string, name: string) => {
        e.stopPropagation(); 
        e.preventDefault();

        const process = processes.find(p => p.id === id);
        if (process) {
            const hasEvidence = process.evidence && process.evidence.trim().length > 0;
            const hasMatrix = Object.keys(process.matrixData).some(k => 
                process.matrixData[k].some(r => r.evidenceInput && r.evidenceInput.trim().length > 0)
            );
            const hasFiles = process.uploadedFiles && process.uploadedFiles.length > 0;

            if (hasEvidence || hasMatrix || hasFiles) {
                if (window.confirm(`Delete process "${name}"? \n\n⚠️ WARNING: This process contains evidence/files that will be permanently lost.`)) {
                    deleteProcess(id);
                    showToast(`Deleted: ${name}`);
                }
            } else {
                deleteProcess(id);
                showToast(`Deleted: ${name}`);
            }
        }
    };

    const triggerRename = (p: AuditProcess) => {
        setEditingProcessId(p.id);
        setEditName(p.name);
    };

    const saveEditing = () => {
        if (editingProcessId && editName.trim()) {
            renameProcess(editingProcessId, editName.trim());
            showToast("Renamed successfully");
        }
        setEditingProcessId(null);
    };

    const displayProcesses = processes.filter(s => s.name && s.name.trim() !== "");
    const activeProcessName = displayProcesses.find(p => p.id === activeProcessId)?.name || "Select Process";

    return (
        <div className="bg-gray-50/80 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-3 space-y-4 w-full">
            <input type="file" ref={fileInputRef} accept=".pdf,.docx,.doc,.txt" className="hidden" onChange={handleFileChange} />

            {/* SECTION 1: STANDARD */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Audit Standard</label>
                <div className="relative group/source">
                    <IconSelect 
                        icon={sourceIcon}
                        iconColor={`${sourceColor} transition-all duration-300 ${cursorClass}`}
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard"
                        onIconClick={handleIconClick}
                        iconTitle={sourceTooltip}
                    />

                    {hasSource && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onClearKnowledge(); }}
                            className="absolute right-9 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-red-500 bg-transparent hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-all z-20 active:scale-95"
                            title="Remove Source File"
                        >
                            <Icon name="Trash2" size={14} />
                        </button>
                    )}

                    {standardKey && (
                        <button onClick={onOpenIntegrity} className={`absolute -top-1.5 -right-1.5 p-1 rounded-full shadow-lg transition-all hover:scale-110 active:scale-95 text-white ring-2 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Integrity Check">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={10}/>
                        </button>
                    )}
                </div>

                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 2: ENTITY & CONTEXT */}
            <div className="space-y-3">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Organization Context</label>
                <div className="grid grid-cols-[1.5fr_1fr] gap-2">
                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="SMO/ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                </div>

                {/* --- PROCESS MANAGEMENT --- */}
                <div className="space-y-2 pt-1">
                    <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-bold text-indigo-500 dark:text-indigo-400 uppercase">Process Management</label>
                        <span className="text-[9px] text-slate-400 dark:text-slate-500 font-mono">{displayProcesses.length} Items</span>
                    </div>

                    {/* CASE A: No Processes */}
                    {displayProcesses.length === 0 ? (
                        <>
                            <div className="relative group w-full">
                                <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-600 dark:text-indigo-400 group-focus-within:text-indigo-500">
                                    <Icon name="Plus" size={16} />
                                </div>
                                <input
                                    ref={processInputRef}
                                    type="text"
                                    value={inputValue}
                                    placeholder="Enter Process/Department..."
                                    onChange={(e) => setInputValue(e.target.value)}
                                    onKeyDown={handleAddKeyDown}
                                    className="w-full pl-10 pr-3 py-2.5 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-700 dark:text-slate-300 placeholder-indigo-300 dark:placeholder-slate-600 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                                    autoComplete="off"
                                />
                            </div>
                            <div className="text-center py-4 text-[10px] text-red-400 font-bold bg-red-50 dark:bg-red-900/20 rounded-lg border border-red-200 dark:border-red-800 animate-pulse">
                                ! ACTION REQUIRED <br/> <span className="font-normal text-slate-500">Create a Process to Start</span>
                            </div>
                        </>
                    ) : (
                        /* CASE B: Processes Exist (Dropdown Mode) */
                        <div className="relative">
                            {/* 1. Header / Trigger / Creator */}
                            <div 
                                onClick={() => { if(!isCreating) setIsProcessMenuOpen(!isProcessMenuOpen); }}
                                className={`w-full flex items-center justify-between p-3 rounded-xl border cursor-pointer transition-all duration-200 ${
                                    isProcessMenuOpen || isCreating 
                                        ? 'border-indigo-500 ring-1 ring-indigo-500 bg-white dark:bg-slate-900 shadow-md z-20' 
                                        : 'bg-white dark:bg-slate-950 border-gray-100 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-slate-700'
                                }`}
                            >
                                <div className="flex items-center gap-3 overflow-hidden flex-1">
                                    <Icon name="Session11_GridAdd" size={16} className="text-indigo-600 dark:text-indigo-400" />
                                    {isCreating ? (
                                        <input
                                            ref={processInputRef}
                                            autoFocus
                                            value={inputValue}
                                            onChange={e => setInputValue(e.target.value)}
                                            onKeyDown={handleAddKeyDown}
                                            onBlur={handleInputBlur}
                                            placeholder="Type Name & Enter to Add..."
                                            className="bg-transparent border-none outline-none text-xs font-bold text-slate-800 dark:text-white placeholder-slate-400 w-full"
                                            onClick={(e) => e.stopPropagation()}
                                            autoComplete="off"
                                        />
                                    ) : (
                                        <span className="text-xs font-bold truncate text-slate-700 dark:text-slate-300">
                                            {activeProcessName}
                                        </span>
                                    )}
                                </div>

                                <div className="flex items-center gap-2">
                                    {!isCreating && (
                                        <div 
                                            className={`p-1 rounded-full ${isProcessMenuOpen ? 'bg-indigo-100 text-indigo-600 dark:bg-slate-800 dark:text-indigo-400' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-400'}`} 
                                            title="Add New Process"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setIsProcessMenuOpen(true); // Open list to show context
                                                setIsCreating(true);
                                                setInputValue("");
                                                setTimeout(() => processInputRef.current?.focus(), 50);
                                            }}
                                        >
                                            <Icon name="Plus" size={14} />
                                        </div>
                                    )}
                                    {isCreating && (
                                        <div 
                                            className="p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-red-500" 
                                            title="Cancel / Close"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setIsCreating(false);
                                                setInputValue("");
                                            }}
                                        >
                                            <Icon name="X" size={14} />
                                        </div>
                                    )}
                                    <Icon name="ChevronDown" size={14} className={`transition-transform duration-300 text-slate-400 ${isProcessMenuOpen ? 'rotate-180' : ''} ${isCreating ? 'hidden' : ''}`} />
                                </div>
                            </div>

                            {/* 2. Collapsible Dropdown Content */}
                            <div className={`overflow-hidden transition-all duration-300 ease-in-out ${isProcessMenuOpen ? 'max-h-[300px] opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
                                <div className="p-1 bg-white dark:bg-slate-950 border border-gray-200 dark:border-slate-800 rounded-xl shadow-xl space-y-1">

                                    {/* The List */}
                                    <div ref={listRef} className="max-h-[200px] overflow-y-auto custom-scrollbar px-1 space-y-1 pb-1 pt-1 scroll-smooth">
                                        {displayProcesses.map(p => {
                                            const isActive = activeProcessId === p.id;
                                            const isEditing = editingProcessId === p.id;

                                            return (
                                                <div 
                                                    key={p.id}
                                                    className={`group flex items-center justify-between p-2 rounded-lg cursor-pointer transition-all ${isActive ? 'bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-900/30' : 'hover:bg-gray-50 dark:hover:bg-slate-800 border border-transparent'}`}
                                                    onClick={() => {
                                                        if(!isEditing) {
                                                            changeProcess(p.id);
                                                            // Keep list open if we are in creation mode, else close
                                                            if (!isCreating) setIsProcessMenuOpen(false); 
                                                        }
                                                    }}
                                                >
                                                    <div className="flex items-center gap-2 overflow-hidden flex-1">
                                                        <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${isActive ? 'bg-indigo-500' : 'bg-slate-300 dark:bg-slate-700'}`}></div>

                                                        {isEditing ? (
                                                            <input 
                                                                autoFocus
                                                                className="w-full min-w-0 bg-white dark:bg-slate-900 text-slate-900 dark:text-white text-xs font-bold px-1 py-0.5 rounded outline-none border border-indigo-300"
                                                                value={editName}
                                                                onChange={e => setEditName(e.target.value)}
                                                                onKeyDown={e => e.key === 'Enter' && saveEditing()}
                                                                onBlur={saveEditing}
                                                                onClick={e => e.stopPropagation()} 
                                                            />
                                                        ) : (
                                                            <span className={`text-xs truncate font-bold ${isActive ? 'text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400'}`}>
                                                                {p.name}
                                                            </span>
                                                        )}
                                                    </div>

                                                    {/* Actions */}
                                                    {!isEditing && (
                                                        <div className="flex items-center gap-1 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                                                            <button 
                                                                type="button"
                                                                onClick={(e) => { e.preventDefault(); e.stopPropagation(); triggerRename(p); }}
                                                                className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-md"
                                                                title="Rename"
                                                            >
                                                                <Icon name="FileEdit" size={12}/>
                                                            </button>

                                                            <button 
                                                                type="button"
                                                                onClick={(e) => handleDeleteClick(e, p.id, p.name)}
                                                                className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md"
                                                                title="Delete"
                                                            >
                                                                <Icon name="Trash2" size={12}/>
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 3: PERSONNEL */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Auditor</label>
                <div className="grid grid-cols-1 gap-2">
                     <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                </div>
            </div>
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { StandardsData, AuditInfo, AuditProcess, Standard, MatrixRow, EvidenceTag, AnalysisResult } from '../types';
import { DEFAULT_AUDIT_INFO, STANDARDS_DATA, INITIAL_EVIDENCE } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Process Management
    processes: AuditProcess[];
    activeProcessId: string | null;
    activeProcess: AuditProcess | undefined;
    setActiveProcessId: (id: string | null) => void;
    addProcess: (name: string) => void;
    renameProcess: (id: string, name: string) => void;
    deleteProcess: (id: string) => void;
    batchUpdateProcessClauses: (updates: { processId: string, clauses: string[] }[]) => void;
    toggleProcessClause: (processId: string, clauseId: string) => void; // NEW FUNCTION

    // Interviewee Management
    addInterviewee: (name: string) => void;
    removeInterviewee: (name: string) => void;

    // Active Data
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections (Global/Legacy - mostly for sidebar highlighting)
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

export const AuditProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);

    // Processes (Start Empty)
    const [processes, setProcesses] = useState<AuditProcess[]>([]);
    const [activeProcessId, setActiveProcessId] = useState<string | null>(null);

    // Active View Data (Synced with Active Process)
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    const standards = { ...STANDARDS_DATA, ...customStandards };

    // Safe fallback
    const activeProcess = processes.find(p => p.id === activeProcessId);

    // --- SYNC EFFECTS ---
    // Save active view data back to process object
    useEffect(() => {
        if (!activeProcessId) return;

        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (p.evidence !== evidence || p.matrixData !== matrixData || p.evidenceTags !== evidenceTags) {
                    return { ...p, evidence, matrixData, evidenceTags };
                }
            }
            return p;
        }));
    }, [evidence, matrixData, evidenceTags, activeProcessId]);

    // Load process data into view when ID changes
    useEffect(() => {
        if (!activeProcessId) {
            setEvidence("");
            setMatrixData({});
            setEvidenceTags([]);
            return;
        }

        const target = processes.find(p => p.id === activeProcessId);
        if (target) {
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
        }
    }, [activeProcessId]);

    // --- ACTIONS ---

    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        // Just delete custom definition
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        // If it was selected, unselect it
        if (standardKey === key) setStandardKey("");
    };

    // Process Actions
    const addProcess = (name: string) => {
        const newId = `proc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;
        const newProcess = { 
            id: newId, 
            name, 
            evidence: "", 
            interviewees: [],
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [] 
        };
        setProcesses(prev => [...prev, newProcess]);
        setActiveProcessId(newId);
    };

    const renameProcess = (id: string, name: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    };

    // FIXED DELETE - Completely separate state updates
    const deleteProcess = (idToDelete: string) => {
        // 1. Determine new Active ID based on current state
        if (activeProcessId === idToDelete) {
            const remaining = processes.filter(p => p.id !== idToDelete);
            const nextId = remaining.length > 0 ? remaining[0].id : null;
            setActiveProcessId(nextId);
        }

        // 2. Update Process List
        setProcesses(prev => prev.filter(p => p.id !== idToDelete));
    };

    // HELPER to find clause details
    const findClauseInStandard = (cid: string, standard: Standard | undefined): any => {
        if (!standard) return null;
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const findRecursive = (id: string, list: any[]): any => {
            for (const c of list) {
                if (c.id === id) return c;
                if (c.subClauses) {
                    const found = findRecursive(id, c.subClauses);
                    if (found) return found;
                }
            }
            return null;
        };
        return findRecursive(cid, allClauses);
    };

    const batchUpdateProcessClauses = (updates: { processId: string, clauses: string[] }[]) => {
        setProcesses(prev => prev.map(p => {
            const update = updates.find(u => u.processId === p.id);
            if (update) {
                const newMatrixData = { ...p.matrixData };
                const standard = standards[standardKey];

                update.clauses.forEach(clauseId => {
                    if (!newMatrixData[clauseId]) {
                        const clause = findClauseInStandard(clauseId, standard);
                        const desc = clause?.description || "Requirement";
                        newMatrixData[clauseId] = [{
                            id: `${clauseId}_req_0`,
                            requirement: desc,
                            evidenceInput: "",
                            status: 'pending'
                        }];
                    }
                });
                return { ...p, matrixData: newMatrixData };
            }
            return p;
        }));

        // Force immediate update if active process is modified
        if (updates.some(u => u.processId === activeProcessId)) {
             const activeUpdate = updates.find(u => u.processId === activeProcessId);
             if (activeUpdate) {
                 setMatrixData(prev => {
                     const next = { ...prev };
                     const standard = standards[standardKey];
                     activeUpdate.clauses.forEach(cid => {
                         if(!next[cid]) {
                             const c = findClauseInStandard(cid, standard);
                             next[cid] = [{ id: `${cid}_req_0`, requirement: c?.description || "Req", evidenceInput: "", status: 'pending' }];
                         }
                     });
                     return next;
                 });
             }
        }
    };

    // NEW FUNCTION: Toggle specific clause for specific process (Add/Remove)
    const toggleProcessClause = (processId: string, clauseId: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id !== processId) return p;

            const newMatrixData = { ...p.matrixData };
            if (newMatrixData[clauseId]) {
                // DELETE
                delete newMatrixData[clauseId];
            } else {
                // ADD
                const standard = standards[standardKey];
                const clause = findClauseInStandard(clauseId, standard);
                const desc = clause?.description || "Requirement";
                newMatrixData[clauseId] = [{
                    id: `${clauseId}_req_0`,
                    requirement: desc,
                    evidenceInput: "",
                    status: 'pending'
                }];
            }
            return { ...p, matrixData: newMatrixData };
        }));

        // If the toggled process is currently active, we must sync the local matrixData state
        if (activeProcessId === processId) {
            setMatrixData(prev => {
                const next = { ...prev };
                if (next[clauseId]) {
                    delete next[clauseId];
                } else {
                    const standard = standards[standardKey];
                    const clause = findClauseInStandard(clauseId, standard);
                    const desc = clause?.description || "Requirement";
                    next[clauseId] = [{
                        id: `${clauseId}_req_0`,
                        requirement: desc,
                        evidenceInput: "",
                        status: 'pending'
                    }];
                }
                return next;
            });
        }
    };

    const addInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (!p.interviewees.includes(name)) {
                    return { ...p, interviewees: [...p.interviewees, name] };
                }
            }
            return p;
        }));
    };

    const removeInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                return { ...p, interviewees: p.interviewees.filter(i => i !== name) };
            }
            return p;
        }));
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) { console.error(e); }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteDocument(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setProcesses([]);
        setActiveProcessId(null);
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);

        if (data.processes && data.processes.length > 0) {
            setProcesses(data.processes);
            if(data.activeProcessId) setActiveProcessId(data.activeProcessId);
        } else if (data.scopes && data.scopes.length > 0) {
             const migrated = data.scopes.map((s: any) => ({
                 ...s,
                 interviewees: [] 
             }));
             setProcesses(migrated);
             if(data.activeScopeId) setActiveProcessId(data.activeScopeId);
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    return (
        <AuditContext.Provider value={{
            standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
            auditInfo, setAuditInfo,
            processes, activeProcessId, activeProcess, setActiveProcessId, addProcess, renameProcess, deleteProcess, batchUpdateProcessClauses, toggleProcessClause,
            addInterviewee, removeInterviewee,
            evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
            selectedClauses, setSelectedClauses,
            knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
            analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
            resetSession, restoreSession
        }}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

interface UIContextType {
    isDarkMode: boolean;
    toggleDarkMode: () => void;
    fontSizeScale: number;
    setFontSizeScale: React.Dispatch<React.SetStateAction<number>>;
    isSidebarOpen: boolean;
    setSidebarOpen: (isOpen: boolean) => void;
    sidebarWidth: number;
    setSidebarWidth: (width: number) => void;

    // Modal State Managers
    modals: {
        settings: boolean;
        about: boolean;
        integrity: boolean;
        recall: boolean;
        addStandard: boolean;
        cmdPalette: boolean;
    };
    toggleModal: (modal: keyof UIContextType['modals'], state?: boolean) => void;

    // Toast
    toastMsg: string | null;
    showToast: (msg: string) => void;
}

const UIContext = createContext<UIContextType | undefined>(undefined);

export const UIProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // Theme
    const [isDarkMode, setIsDarkMode] = useState(true);
    useEffect(() => {
        if (isDarkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [isDarkMode]);

    // Font
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
    }, [fontSizeScale]);

    // Layout
    const [isSidebarOpen, setSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420);

    // Modals
    const [modals, setModals] = useState({
        settings: false,
        about: false,
        integrity: false,
        recall: false,
        addStandard: false,
        cmdPalette: false,
    });

    const toggleModal = (modal: keyof typeof modals, state?: boolean) => {
        setModals(prev => ({ ...prev, [modal]: state ?? !prev[modal] }));
    };

    // Toast
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const showToast = (msg: string) => setToastMsg(msg);

    return (
        <UIContext.Provider value={{
            isDarkMode,
            toggleDarkMode: () => setIsDarkMode(prev => !prev),
            fontSizeScale,
            setFontSizeScale,
            isSidebarOpen,
            setSidebarOpen,
            sidebarWidth,
            setSidebarWidth,
            modals,
            toggleModal,
            toastMsg,
            showToast
        }}>
            {children}
        </UIContext.Provider>
    );
};

export const useUI = () => {
    const context = useContext(UIContext);
    if (!context) throw new Error("useUI must be used within UIProvider");
    return context;
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { ApiKeyProfile } from '../types';
import { MODEL_HIERARCHY, MY_FIXED_KEYS } from '../constants';
import { validateApiKey } from '../services/geminiService';

interface KeyPoolContextType {
    apiKeys: ApiKeyProfile[];
    activeKeyId: string;
    isCheckingKey: boolean;
    addKey: (key: string, label?: string) => Promise<boolean>;
    deleteKey: (id: string) => void;
    refreshKeyStatus: (id: string) => Promise<void>;
    checkAllKeys: () => Promise<void>;
    getActiveKey: () => ApiKeyProfile | undefined;
    isAutoCheckEnabled: boolean;
    toggleAutoCheck: (enabled: boolean) => void;
    setActiveKeyId: (id: string) => void;
}

const KeyPoolContext = createContext<KeyPoolContextType | undefined>(undefined);

export const KeyPoolProvider = ({ children }: React.PropsWithChildren<{}>) => {
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);
    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);

    // Initial Load
    useEffect(() => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;

            // Inject Environment Keys if not present
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (fixedKey && !existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ 
                        id: `env_key_${index}_${Math.random().toString(36).substr(2, 5)}`, 
                        label: `Env Key ${index + 1}`, 
                        key: fixedKey, 
                        status: 'unknown', 
                        latency: 0, 
                        lastChecked: new Date().toISOString() 
                    });
                    hasChanges = true;
                }
            });

            setApiKeys(loadedKeys);
            if(hasChanges) localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));

            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) {
                setActiveKeyId(savedActiveId);
            } else if (loadedKeys.length > 0) {
                setActiveKeyId(loadedKeys[0].id);
            }

            // Auto-check init
            const autoCheck = localStorage.getItem('iso_auto_check') === 'true';
            setIsAutoCheckEnabled(autoCheck);

        } catch (e) { console.error("Key Load Error", e); }
    }, []);

    // Background Check Loop
    useEffect(() => {
        if (!isAutoCheckEnabled) return;
        const interval = setInterval(() => {
            if (!isCheckingKey && apiKeys.length > 0) performBackgroundHealthCheck();
        }, 60000);
        return () => clearInterval(interval);
    }, [isAutoCheckEnabled, isCheckingKey, apiKeys]);

    const performBackgroundHealthCheck = async () => {
        // Find oldest checked key
        const sorted = [...apiKeys].sort((a, b) => new Date(a.lastChecked || 0).getTime() - new Date(b.lastChecked || 0).getTime());
        const candidate = sorted[0];
        if (candidate) await refreshKeyStatus(candidate.id);
    };

    const determineCapabilities = async (key: string) => {
        const result = await validateApiKey(key);
        return {
            status: result.isValid ? 'valid' : (result.errorType || 'unknown'),
            activeModel: result.activeModel,
            latency: result.latency,
            errorMessage: result.errorMessage
        };
    };

    const addKey = async (key: string, label?: string) => {
        if (!key.trim()) return false;
        if (apiKeys.some(k => k.key === key.trim())) return false;

        setIsCheckingKey(true);
        const caps = await determineCapabilities(key);

        const newProfile: ApiKeyProfile = {
            id: Date.now().toString(),
            label: label || `Key ${apiKeys.length + 1}`,
            key: key.trim(),
            status: caps.status as any,
            activeModel: caps.activeModel,
            latency: caps.latency,
            lastChecked: new Date().toISOString()
        };

        const newKeys = [...apiKeys, newProfile];
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        if (apiKeys.length === 0 || caps.status === 'valid') {
            setActiveKeyId(newProfile.id);
            localStorage.setItem("iso_active_key_id", newProfile.id);
        }

        setIsCheckingKey(false);
        return caps.status === 'valid';
    };

    const deleteKey = (id: string) => {
        const newKeys = apiKeys.filter(k => k.id !== id);
        setApiKeys(newKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(newKeys));

        if (activeKeyId === id) {
            const next = newKeys.find(k => k.status === 'valid') || newKeys[0];
            const nextId = next ? next.id : "";
            setActiveKeyId(nextId);
            if(nextId) localStorage.setItem("iso_active_key_id", nextId);
            else localStorage.removeItem("iso_active_key_id");
        }
    };

    const refreshKeyStatus = async (id: string) => {
        const profile = apiKeys.find(k => k.id === id);
        if(!profile) return;

        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, status: 'checking' } : k));
        const caps = await determineCapabilities(profile.key);

        setApiKeys(prev => {
            const next = prev.map(k => k.id === id ? {
                ...k,
                status: caps.status as any,
                activeModel: caps.activeModel || k.activeModel,
                latency: caps.latency,
                lastChecked: new Date().toISOString()
            } : k);
            localStorage.setItem("iso_api_keys", JSON.stringify(next));
            return next;
        });
    };

    const checkAllKeys = async () => {
        setIsCheckingKey(true);
        for(const k of apiKeys) {
            await refreshKeyStatus(k.id);
        }
        setIsCheckingKey(false);
    };

    const toggleAutoCheck = (enabled: boolean) => {
        setIsAutoCheckEnabled(enabled);
        localStorage.setItem('iso_auto_check', String(enabled));
    };

    const getActiveKey = useCallback(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);

    return (
        <KeyPoolContext.Provider value={{
            apiKeys, activeKeyId, isCheckingKey, addKey, deleteKey, refreshKeyStatus,
            checkAllKeys, getActiveKey, isAutoCheckEnabled, toggleAutoCheck, setActiveKeyId
        }}>
            {children}
        </KeyPoolContext.Provider>
    );
};

export const useKeyPool = () => {
    const context = useContext(KeyPoolContext);
    if (!context) throw new Error("useKeyPool must be used within KeyPoolProvider");
    return context;
};

import React, { useState } from 'react';
import { Icon } from '../UI';
import { Standard, Clause } from '../../types';
import { copyToClipboard } from '../../utils';

interface StandardExplorerProps {
    standard: Standard | undefined;
    standardKey: string;
    selectedClauses: string[]; // Kept for highlighting active context if needed, but not modification
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>; // Kept for API compat, but unused for toggling
    onReferenceClause: (clause: Clause) => void;
    repairedIds: string[];
    onScrollTrigger?: () => void;
}

export const StandardExplorer: React.FC<StandardExplorerProps> = ({
    standard, standardKey, onReferenceClause, repairedIds, onScrollTrigger
}) => {
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    // Helper to restore distinctive colors for groups
    const getGroupStyle = (id: string) => {
        const key = id.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 hover:bg-orange-100 dark:bg-orange-900/20 dark:hover:bg-orange-900/30 text-orange-700 dark:text-orange-400';
        if (key.includes('SUPPORT')) return 'bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/20 dark:hover:bg-blue-900/30 text-blue-700 dark:text-blue-400';
        if (key.includes('DO')) return 'bg-cyan-50 hover:bg-cyan-100 dark:bg-cyan-900/20 dark:hover:bg-cyan-900/30 text-cyan-700 dark:text-cyan-400';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:hover:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400';
        if (key.includes('ANNEX')) return 'bg-purple-50 hover:bg-purple-100 dark:bg-purple-900/20 dark:hover:bg-purple-900/30 text-purple-700 dark:text-purple-400';
        return 'bg-gray-50 hover:bg-gray-100 dark:bg-slate-800/30 dark:hover:bg-slate-800 text-slate-700 dark:text-slate-300';
    };

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id);
        const isCopied = copiedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-3 pl-3 border-l dark:border-slate-800' : ''}`}>
                <div 
                    className={`group flex items-start gap-2 p-1.5 rounded-lg transition-all duration-200 ease-soft cursor-pointer ${isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/80 dark:hover:bg-slate-800/50'}`}
                    onClick={() => hasSubs && toggleClauseExpand(c.id)}
                >
                    <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-2 flex-wrap">
                                <span className={`text-[10px] font-black uppercase shrink-0 px-1.5 py-0.5 rounded border ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-700' : 'bg-transparent border-transparent text-slate-400'}`}>
                                    {c.code}
                                </span>
                                <span className={`text-xs font-medium tracking-tight leading-tight ${level === 0 ? 'text-slate-800 dark:text-slate-200' : 'text-slate-600 dark:text-slate-400'}`}>
                                    {c.title}
                                </span>
                                {isRepaired && <span className="text-[8px] font-black bg-emerald-100 text-emerald-600 px-1 py-0.5 rounded animate-pulse">FIX</span>}
                            </div>

                            {/* Hover Actions */}
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1 text-slate-400 hover:text-indigo-500 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded" title="Read Content">
                                    <Icon name="BookOpen" size={12} />
                                </button>
                                <button
                                    onClick={(e) => handleSingleClauseCopy(e, c)}
                                    className={`p-1 ${isCopied ? 'text-emerald-500' : 'text-slate-400 hover:text-indigo-500'} hover:bg-gray-100 dark:hover:bg-slate-800 rounded`}
                                    title="Copy Title"
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={12} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={10} className={`text-slate-300 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        {level === 0 && (
                            <div className="text-[10px] text-slate-400 dark:text-slate-500 italic mt-0.5 line-clamp-2">
                                {c.description}
                            </div>
                        )}
                    </div>
                </div>

                {/* Accordion Body */}
                {hasSubs && isExpanded && (
                    <div className="mt-0.5 flex flex-col animate-accordion-down overflow-hidden">
                        {c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-white dark:bg-slate-950 w-full md:min-w-[390px]">
            <div className="p-3 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 sticky top-0 z-10 backdrop-blur-sm">
                <div className="flex items-center justify-between">
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                        <Icon name="Book" size={12}/> Reference Explorer
                    </span>
                    <span className="text-[9px] text-slate-300 bg-slate-100 dark:bg-slate-800 dark:text-slate-600 px-1.5 py-0.5 rounded">
                        Read-Only
                    </span>
                </div>
            </div>

            <div 
                className="flex-1 overflow-y-auto custom-scrollbar p-3 scroll-smooth"
                onScroll={(e) => {
                    if (e.currentTarget.scrollTop > 30 && onScrollTrigger) onScrollTrigger();
                }}
            >
                <div className="flex flex-col gap-3 pb-12">
                    {!standard ? (
                        <div className="text-center text-slate-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>
                    ) : (
                        standard.groups.map(g => {
                            const isGroupExpanded = expandedGroups.includes(g.id);
                            const groupColorStyle = getGroupStyle(g.id);

                            return (
                                <div key={g.id} className="bg-white dark:bg-slate-900 rounded-xl border border-gray-100 dark:border-slate-800 overflow-hidden transition-all duration-300">
                                    <div 
                                        className={`flex items-center justify-between p-3 cursor-pointer transition-colors select-none ${groupColorStyle}`} 
                                        onClick={() => toggleGroupExpand(g.id)}
                                    >
                                        <div className="flex items-center gap-2.5">
                                            <div className="p-1.5 rounded-lg bg-white/60 dark:bg-black/20 shadow-sm">
                                                <Icon name={g.icon} size={14}/>
                                            </div>
                                            <h4 className="text-xs font-black uppercase tracking-wider opacity-90">{g.title}</h4>
                                        </div>
                                        <Icon name="ChevronDown" size={12} className={`transition-transform duration-300 opacity-60 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                                    </div>

                                    {isGroupExpanded && (
                                        <div className="p-2 space-y-1 bg-white dark:bg-slate-900 border-t border-gray-100 dark:border-slate-800 animate-accordion-down">
                                             {g.clauses.map(c => renderClauseItem(c))}
                                        </div>
                                    )}
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useRef } from 'react';
import { Icon } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { Clause } from '../../types';
import { useUI } from '../../contexts/UIContext';
import { cleanFileName } from '../../utils';

export const PlanningView = () => {
    const { 
        standards, standardKey, processes, 
        addProcess, batchUpdateProcessClauses, toggleProcessClause
    } = useAudit();

    const { showToast, setSidebarOpen } = useUI();
    const [search, setSearch] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    const currentStandard = standards[standardKey];

    // Helper: Restore distinctive colors for groups (Duplicated logic for consistent styling)
    const getGroupStyle = (id: string) => {
        const key = id.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 dark:bg-orange-900/20 text-orange-800 dark:text-orange-300 border-orange-200 dark:border-orange-800';
        if (key.includes('SUPPORT')) return 'bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-300 border-blue-200 dark:border-blue-800';
        if (key.includes('DO')) return 'bg-cyan-50 dark:bg-cyan-900/20 text-cyan-800 dark:text-cyan-300 border-cyan-200 dark:border-cyan-800';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-300 border-emerald-200 dark:border-emerald-800';
        if (key.includes('ANNEX')) return 'bg-purple-50 dark:bg-purple-900/20 text-purple-800 dark:text-purple-300 border-purple-200 dark:border-purple-800';
        return 'bg-gray-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 border-gray-200 dark:border-slate-700';
    };

    // Flatten logic that preserves hierarchy level
    const getGroupClauses = (clauses: Clause[]) => {
        const flat: { clause: Clause, level: number }[] = [];
        const traverse = (list: Clause[], level: number) => {
            list.forEach(c => {
                flat.push({ clause: c, level });
                if(c.subClauses) traverse(c.subClauses, level + 1);
            });
        };
        traverse(clauses, 0);
        return flat;
    };

    const isPlanned = (processId: string, clauseId: string) => {
        const proc = processes.find(p => p.id === processId);
        return proc ? !!proc.matrixData[clauseId] : false;
    };

    const handleToggle = (processId: string, clauseId: string) => {
        toggleProcessClause(processId, clauseId);
    };

    // New: Batch toggle for a whole group within a process
    const handleGroupToggle = (processId: string, clausesInGroup: Clause[]) => {
        const flatIds: string[] = [];
        const traverse = (list: Clause[]) => list.forEach(c => {
            flatIds.push(c.id);
            if(c.subClauses) traverse(c.subClauses);
        });
        traverse(clausesInGroup);

        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        // Check if all are currently selected
        const allSelected = flatIds.every(cid => !!proc.matrixData[cid]);

        // If all selected, we want to REMOVE all. If mixed or none, we want to ADD all.
        if (allSelected) {
            // Remove individually (batch remove logic not in context yet, loop is safe for local state)
            flatIds.forEach(cid => {
                if (proc.matrixData[cid]) toggleProcessClause(processId, cid);
            });
        } else {
            // Add missing ones
            const toAdd = flatIds.filter(cid => !proc.matrixData[cid]);
            batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
        }
    };

    // Coverage Stats Logic
    const coverageStats = useMemo(() => {
        if (!currentStandard) return { percent: 0, covered: 0, total: 0 };
        let total = 0;
        const traverse = (list: Clause[]) => list.forEach(c => { total++; if(c.subClauses) traverse(c.subClauses); });
        currentStandard.groups.forEach(g => traverse(g.clauses));

        if (total === 0) return { percent: 0, covered: 0, total: 0 };

        const coveredSet = new Set<string>();
        processes.forEach(p => {
            Object.keys(p.matrixData).forEach(cid => coveredSet.add(cid));
        });

        return {
            percent: Math.round((coveredSet.size / total) * 100),
            covered: coveredSet.size,
            total: total
        };
    }, [currentStandard, processes]);

    const radius = 24;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (coverageStats.percent / 100) * circumference;

    // Filter Logic
    const filteredGroups = useMemo(() => {
        if (!currentStandard) return [];
        if (!search) return currentStandard.groups;

        const term = search.toLowerCase();
        // Deep filter groups
        return currentStandard.groups.map(g => {
            const matchingClauses = g.clauses.filter(c => {
                const matchSelf = c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term);
                const matchSub = c.subClauses?.some(s => s.code.toLowerCase().includes(term) || s.title.toLowerCase().includes(term));
                return matchSelf || matchSub;
            });
            return matchingClauses.length > 0 ? { ...g, clauses: matchingClauses } : null;
        }).filter(g => g !== null) as typeof currentStandard.groups;
    }, [currentStandard, search]);


    // --- Template Import/Export (Existing Logic Kept) ---
    const handleExportTemplate = () => {
        if (processes.length === 0) { showToast("No processes to export."); return; }
        const templateData = processes.map(p => ({ name: p.name, clauses: Object.keys(p.matrixData) }));
        const blob = new Blob([JSON.stringify(templateData, null, 2)], { type: "application/json" });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.download = `${cleanFileName(currentStandard.name)}_Plan.json`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast("Template exported.");
    };

    const handleImportTemplate = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const content = ev.target?.result as string;
                const templateData = JSON.parse(content);
                if (!Array.isArray(templateData)) throw new Error("Invalid format");

                templateData.forEach((item: any) => {
                    if (item.name) addProcess(item.name); 
                    // Note: Clause mapping omitted due to async ID generation in this version
                });
                showToast(`Imported ${templateData.length} processes structure.`);
            } catch (err) { showToast("Import failed."); }
        };
        reader.readAsText(file);
        e.target.value = '';
    };

    if (!currentStandard) return (
        <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-2xl border border-dashed border-gray-200 dark:border-slate-800 m-4">
            <Icon name="Book" size={48} className="mb-4 opacity-20"/>
            <p className="font-bold text-slate-500">No Standard Selected</p>
            <button onClick={() => setSidebarOpen(true)} className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg text-xs font-bold flex items-center gap-2">
                <Icon name="LayoutList" size={16}/> Select Standard
            </button>
        </div>
    );

    return (
        <div className="h-full flex flex-col animate-fade-in-up gap-4 relative">

            {/* Header / Stats */}
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center justify-between shrink-0">
                <div className="flex items-center gap-6">
                    <div className="relative w-16 h-16 flex items-center justify-center shrink-0">
                        <svg className="transform -rotate-90 w-16 h-16">
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100 dark:text-slate-800" />
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" strokeDasharray={circumference} strokeDashoffset={strokeDashoffset} className="text-indigo-500 transition-all duration-1000 ease-out" strokeLinecap="round" />
                        </svg>
                        <span className="absolute text-xs font-black text-slate-700 dark:text-white">{coverageStats.percent}%</span>
                    </div>
                    <div className="flex flex-col gap-1">
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">{currentStandard.name}</h3>
                        <p className="text-xs text-slate-500">
                            <span className="font-bold text-indigo-500">{coverageStats.covered}</span> of {coverageStats.total} clauses mapped.
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"><Icon name="Search" size={14}/></div>
                        <input 
                            className="w-full pl-9 pr-3 py-2 rounded-xl bg-gray-50 dark:bg-slate-950 border border-gray-200 dark:border-slate-700 text-xs outline-none focus:border-orange-500"
                            placeholder="Filter clauses..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                    </div>

                    <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleImportTemplate} />
                    <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all" title="Import Plan">
                        <Icon name="UploadCloud" size={16}/>
                    </button>
                    <button onClick={handleExportTemplate} className="p-2 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all" title="Export Plan">
                        <Icon name="Download" size={16}/>
                    </button>
                </div>
            </div>

            {/* MATRIX CONTAINER */}
            <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 overflow-hidden shadow-sm relative flex flex-col">
                {processes.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
                        <p className="mb-4">No processes defined.</p>
                        <div className="p-4 border-2 border-dashed border-indigo-200 dark:border-indigo-900/50 rounded-xl bg-indigo-50 dark:bg-indigo-900/10 text-indigo-500">
                            Create processes in the sidebar to begin planning.
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 overflow-auto custom-scrollbar relative">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-gray-50 dark:bg-slate-950 sticky top-0 z-30 shadow-sm">
                                <tr>
                                    <th className="p-3 text-[10px] font-bold text-slate-500 uppercase tracking-wider border-b border-r border-gray-200 dark:border-slate-800 sticky left-0 bg-gray-50 dark:bg-slate-950 z-40 min-w-[250px]">
                                        Clause Reference
                                    </th>
                                    {processes.map(p => (
                                        <th key={p.id} className="p-3 text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider border-b border-gray-200 dark:border-slate-800 min-w-[120px] text-center">
                                            <div className="flex flex-col items-center gap-1">
                                                <span className="truncate max-w-[100px]" title={p.name}>{p.name}</span>
                                                <span className="text-[8px] bg-indigo-100 dark:bg-indigo-900/30 px-1.5 py-0.5 rounded text-indigo-700 dark:text-indigo-300 font-mono">
                                                    {Object.keys(p.matrixData).length}
                                                </span>
                                            </div>
                                        </th>
                                    ))}
                                </tr>
                            </thead>

                            <tbody className="divide-y divide-gray-100 dark:divide-slate-800/50">
                                {filteredGroups.map(group => {
                                    const groupStyle = getGroupStyle(group.id);
                                    const groupFlatList = getGroupClauses(group.clauses);

                                    return (
                                        <React.Fragment key={group.id}>
                                            {/* GROUP HEADER ROW */}
                                            <tr className={`sticky z-20 ${groupStyle}`}>
                                                <td className="p-2 border-r border-black/5 dark:border-white/5 font-black text-xs uppercase tracking-widest sticky left-0 z-20 bg-inherit shadow-sm">
                                                    <div className="flex items-center gap-2">
                                                        <Icon name={group.icon} size={14} className="opacity-70"/>
                                                        {group.title}
                                                    </div>
                                                </td>
                                                {processes.map(p => (
                                                    <td key={`group_action_${p.id}_${group.id}`} className="p-2 text-center bg-inherit">
                                                        <button 
                                                            onClick={() => handleGroupToggle(p.id, group.clauses)}
                                                            className="text-[9px] font-bold uppercase tracking-wider opacity-60 hover:opacity-100 bg-white/50 dark:bg-black/20 hover:bg-white dark:hover:bg-black/40 px-2 py-1 rounded transition-all"
                                                        >
                                                            Select Group
                                                        </button>
                                                    </td>
                                                ))}
                                            </tr>

                                            {/* CLAUSE ROWS */}
                                            {groupFlatList.map(({ clause, level }) => (
                                                <tr key={clause.id} className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group">
                                                    <td className="p-2 border-r border-gray-100 dark:border-slate-800 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-gray-50 dark:group-hover:bg-slate-800/30 z-10">
                                                        <div className={`flex items-center gap-2 ${level > 0 ? 'ml-4 border-l-2 border-gray-200 dark:border-slate-800 pl-2' : ''}`}>
                                                            <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300' : 'text-slate-400'}`}>
                                                                {clause.code}
                                                            </span>
                                                            <div className="flex flex-col min-w-0">
                                                                <span className={`text-xs truncate ${level === 0 ? 'font-bold text-slate-800 dark:text-slate-200' : 'font-medium text-slate-600 dark:text-slate-400'}`}>
                                                                    {clause.title}
                                                                </span>
                                                                {level === 0 && <span className="text-[9px] text-slate-400 truncate hidden md:block opacity-70">{clause.description}</span>}
                                                            </div>
                                                        </div>
                                                    </td>
                                                    {processes.map(p => {
                                                        const active = isPlanned(p.id, clause.id);
                                                        return (
                                                            <td key={`${p.id}_${clause.id}`} className="p-1 text-center border-r border-gray-50 dark:border-slate-800/50 last:border-0 relative">
                                                                <div className="flex justify-center">
                                                                    <button
                                                                        onClick={() => handleToggle(p.id, clause.id)}
                                                                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-200 ${
                                                                            active 
                                                                                ? 'bg-emerald-500 text-white shadow-sm shadow-emerald-500/40 transform scale-105' 
                                                                                : 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-300'
                                                                        }`}
                                                                        title={active ? "Planned" : "Click to Plan"}
                                                                    >
                                                                        {active && <Icon name="CheckThick" size={14}/>}
                                                                    </button>
                                                                </div>
                                                            </td>
                                                        );
                                                    })}
                                                </tr>
                                            ))}
                                        </React.Fragment>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { Icon } from './UI';
import { STANDARDS_DATA } from '../constants';
import { generateMissingDescriptions } from '../services/geminiService';
import { AuditInfoForm } from './sidebar/AuditInfoForm';
import { IntegrityModal } from './modals/IntegrityModal';
import { cleanAndParseJSON } from '../utils';
import { useResizable } from '../hooks/useResizable';

// Contexts
import { useAudit } from '../contexts/AuditContext';
import { useUI } from '../contexts/UIContext';
import { useStandardHealth } from '../hooks/useStandardHealth';

interface SidebarProps {
    isOpen: boolean;
    width: number;
    setWidth: (w: number) => void;
}

const Sidebar: React.FC<SidebarProps> = React.memo(({ isOpen, width, setWidth }) => {
    const [isMissionExpanded, setIsMissionExpanded] = useState(true);

    // Correctly pass setWidth to update parent state when dragging ends
    const { isResizing, sidebarRef, startResizing } = useResizable(width, 300, 800, setWidth);

    // Integrity Logic State
    const [isRepairing, setIsRepairing] = useState(false);
    const [repairStats, setRepairStats] = useState<{ fixed: number, cleaned: number } | null>(null);
    const [repairedIds, setRepairedIds] = useState<string[]>([]);

    // Consume Context
    const { 
        standards, standardKey, setStandardKey, updateStandard, resetStandard, addCustomStandard,
        auditInfo, setAuditInfo,
        knowledgeBase, knowledgeFileName, setKnowledgeData, clearKnowledge,
        processes, activeProcessId, addProcess, renameProcess, deleteProcess, setActiveProcessId
    } = useAudit();

    const { modals, toggleModal } = useUI();

    const health = useStandardHealth(standards, standardKey, knowledgeBase);

    const handleAutoRepair = async () => {
        if (!standardKey || !standards[standardKey]) return;
        setIsRepairing(true);
        setRepairStats(null);
        try {
            const currentStandard = JSON.parse(JSON.stringify(standards[standardKey])); 
            const missingClauses: any[] = [];
            const fixedIds: string[] = [];
            let duplicateRemovedCount = 0;

            const findMissing = (list: any[]) => {
                list.forEach(c => {
                    if (!c.description || c.description.trim().length < 5) {
                        missingClauses.push({ ref: c, code: c.code, title: c.title });
                    }
                    if (c.subClauses) findMissing(c.subClauses);
                });
            };
            currentStandard.groups.forEach((g: any) => findMissing(g.clauses));

            if (missingClauses.length > 0) {
                const targets = missingClauses.map(i => ({ code: i.code, title: i.title }));
                const jsonStr = await generateMissingDescriptions(targets);
                const descriptions = cleanAndParseJSON(jsonStr);

                if (Array.isArray(descriptions)) {
                    const descMap = descriptions.reduce((acc: any, item: any) => {
                        if(item.code && item.description) acc[item.code] = item.description;
                        return acc;
                    }, {});
                    missingClauses.forEach(item => {
                        if (descMap[item.code]) {
                            item.ref.description = descMap[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                }
            }
            updateStandard(currentStandard);
            setRepairedIds(fixedIds);
            setRepairStats({ fixed: fixedIds.length, cleaned: duplicateRemovedCount });
        } catch (e) {
            console.error("Repair failed", e);
            alert("Failed to repair automatically.");
        } finally {
            setIsRepairing(false);
        }
    };

    const standardOptions = (() => {
        const rawOptions = Object.keys(standards).map(k => ({ value: k, label: standards[k].name }));
        return [...rawOptions, {value: "ADD_NEW", label: "+ Add New Standard..."}];
    })();

    const infoCompletion = (() => {
        let score = 0;
        if (standardKey) score++;
        if (auditInfo.type) score++;
        if (auditInfo.company) score++;
        if (auditInfo.auditor) score++;
        return Math.min(4, score); 
    })();

    return (
        <div 
            ref={sidebarRef}
            className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl z-50 relative shrink-0 ${isResizing ? 'transition-none' : 'transition-[width] duration-300 ease-soft'} h-full`} 
            style={{ width: isOpen ? (window.innerWidth < 768 ? '100%' : width) : 0 }}
        >
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 transition-colors z-50 group resize-handle hidden md:block" onMouseDown={(e) => { e.preventDefault(); startResizing(); }} />}

            <div className={`flex-1 bg-white dark:bg-slate-900 w-full md:min-w-[390px] flex flex-col transition-all duration-400 ease-soft overflow-hidden`}>
                <div 
                    className="flex-shrink-0 flex items-center justify-between p-4 cursor-pointer group select-none hover:bg-gray-50 dark:hover:bg-slate-800/50 border-b border-gray-200 dark:border-slate-800"
                    onClick={() => setIsMissionExpanded(!isMissionExpanded)}
                >
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 group-hover:text-indigo-500 transition-colors">
                        <Icon name="Session8_Flag" size={14} className="text-indigo-500"/>
                        Audit Mission Charter
                    </h3>
                    <div className="flex gap-2" onClick={(e) => e.stopPropagation()}>
                        <div className="flex gap-0.5 items-center">
                            {[1, 2, 3, 4].map(step => (
                                <div key={step} className={`w-3 h-1 rounded-full ${step <= infoCompletion ? 'bg-indigo-500' : 'bg-gray-200 dark:bg-slate-700'}`}></div>
                            ))}
                        </div>
                        <Icon name="ChevronDown" size={14} className={`text-slate-400 transition-transform duration-300 ${isMissionExpanded ? 'rotate-180' : ''}`} />
                    </div>
                </div>

                <div className={`flex-1 min-h-0 grid transition-all duration-300 ease-in-out ${isMissionExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden flex flex-col">
                        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 pt-0 pb-4">
                            <AuditInfoForm 
                                standards={standards}
                                standardKey={standardKey}
                                setStandardKey={setStandardKey}
                                auditInfo={auditInfo}
                                setAuditInfo={setAuditInfo}
                                onAddNewStandard={() => toggleModal('addStandard', true)}
                                onOpenIntegrity={() => toggleModal('integrity', true)}
                                knowledgeFileName={knowledgeFileName}
                                onKnowledgeUpload={(e) => {/* Handle in context */}}
                                onClearKnowledge={clearKnowledge}
                                health={health}
                                auditFieldIconColor="text-indigo-700 dark:text-indigo-400"
                                standardOptions={standardOptions}
                                scopes={processes}
                                activeScopeId={activeProcessId}
                                onAddScope={addProcess}
                                onChangeScope={setActiveProcessId}
                                onRenameScope={renameProcess}
                                onDeleteScope={deleteProcess}
                            />
                        </div>
                    </div>
                </div>
            </div>

            <IntegrityModal 
                isOpen={modals.integrity}
                onClose={() => toggleModal('integrity', false)}
                health={health}
                isCustomStandard={!!standardKey && !STANDARDS_DATA[standardKey]}
                onResetStandard={() => { resetStandard(standardKey); toggleModal('integrity', false); }}
                onAutoRepair={handleAutoRepair}
                isRepairing={isRepairing}
                repairStats={repairStats}
            />
        </div>
    );
});
export default Sidebar;

import React, { useState, useMemo, useRef } from 'react';
import { Icon } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { Clause } from '../../types';
import { useUI } from '../../contexts/UIContext';
import { cleanFileName } from '../../utils';

export const PlanningView = () => {
    const { 
        standards, standardKey, processes, 
        addProcess, batchUpdateProcessClauses, toggleProcessClause
    } = useAudit();

    const { showToast, setSidebarOpen } = useUI();
    const [search, setSearch] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);
    const searchInputRef = useRef<HTMLInputElement>(null);

    // Collapsible States
    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());
    const [expandedDescriptions, setExpandedDescriptions] = useState<Set<string>>(new Set());

    const currentStandard = standards[standardKey];

    // Helper: Restore distinctive colors for groups (Duplicated logic for consistent styling)
    const getGroupStyle = (id: string) => {
        const key = id.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 dark:bg-orange-900/20 text-orange-800 dark:text-orange-300 border-orange-200 dark:border-orange-800';
        if (key.includes('SUPPORT')) return 'bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-300 border-blue-200 dark:border-blue-800';
        if (key.includes('DO')) return 'bg-cyan-50 dark:bg-cyan-900/20 text-cyan-800 dark:text-cyan-300 border-cyan-200 dark:border-cyan-800';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-300 border-emerald-200 dark:border-emerald-800';
        if (key.includes('ANNEX')) return 'bg-purple-50 dark:bg-purple-900/20 text-purple-800 dark:text-purple-300 border-purple-200 dark:border-purple-800';
        return 'bg-gray-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 border-gray-200 dark:border-slate-700';
    };

    // Flatten logic that preserves hierarchy level
    const getGroupClauses = (clauses: Clause[]) => {
        const flat: { clause: Clause, level: number }[] = [];
        const traverse = (list: Clause[], level: number) => {
            list.forEach(c => {
                flat.push({ clause: c, level });
                if(c.subClauses) traverse(c.subClauses, level + 1);
            });
        };
        traverse(clauses, 0);
        return flat;
    };

    const isPlanned = (processId: string, clauseId: string) => {
        const proc = processes.find(p => p.id === processId);
        return proc ? !!proc.matrixData[clauseId] : false;
    };

    const handleToggle = (processId: string, clauseId: string) => {
        toggleProcessClause(processId, clauseId);
    };

    // New: Batch toggle for a whole group within a process
    const handleGroupToggle = (e: React.MouseEvent, processId: string, clausesInGroup: Clause[]) => {
        e.stopPropagation();
        const flatIds: string[] = [];
        const traverse = (list: Clause[]) => list.forEach(c => {
            flatIds.push(c.id);
            if(c.subClauses) traverse(c.subClauses);
        });
        traverse(clausesInGroup);

        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        // Check if all are currently selected
        const allSelected = flatIds.every(cid => !!proc.matrixData[cid]);

        // If all selected, we want to REMOVE all. If mixed or none, we want to ADD all.
        if (allSelected) {
            // Remove individually (batch remove logic not in context yet, loop is safe for local state)
            flatIds.forEach(cid => {
                if (proc.matrixData[cid]) toggleProcessClause(processId, cid);
            });
        } else {
            // Add missing ones
            const toAdd = flatIds.filter(cid => !proc.matrixData[cid]);
            batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
        }
    };

    const toggleGroupCollapse = (groupId: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupId)) next.delete(groupId);
            else next.add(groupId);
            return next;
        });
    };

    const toggleDescriptionExpand = (clauseId: string) => {
        setExpandedDescriptions(prev => {
            const next = new Set(prev);
            if (next.has(clauseId)) next.delete(clauseId);
            else next.add(clauseId);
            return next;
        });
    };

    // Coverage Stats Logic
    const coverageStats = useMemo(() => {
        if (!currentStandard) return { percent: 0, covered: 0, total: 0 };
        let total = 0;
        const traverse = (list: Clause[]) => list.forEach(c => { total++; if(c.subClauses) traverse(c.subClauses); });
        currentStandard.groups.forEach(g => traverse(g.clauses));

        if (total === 0) return { percent: 0, covered: 0, total: 0 };

        const coveredSet = new Set<string>();
        processes.forEach(p => {
            Object.keys(p.matrixData).forEach(cid => coveredSet.add(cid));
        });

        return {
            percent: Math.round((coveredSet.size / total) * 100),
            covered: coveredSet.size,
            total: total
        };
    }, [currentStandard, processes]);

    const radius = 24;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (coverageStats.percent / 100) * circumference;

    // Filter Logic
    const filteredGroups = useMemo(() => {
        if (!currentStandard) return [];
        if (!search) return currentStandard.groups;

        const term = search.toLowerCase();
        // Deep filter groups
        return currentStandard.groups.map(g => {
            const matchingClauses = g.clauses.filter(c => {
                const matchSelf = c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term);
                const matchSub = c.subClauses?.some(s => s.code.toLowerCase().includes(term) || s.title.toLowerCase().includes(term));
                return matchSelf || matchSub;
            });
            return matchingClauses.length > 0 ? { ...g, clauses: matchingClauses } : null;
        }).filter(g => g !== null) as typeof currentStandard.groups;
    }, [currentStandard, search]);


    // --- Template Import/Export (Existing Logic Kept) ---
    const handleExportTemplate = () => {
        if (processes.length === 0) { showToast("No processes to export."); return; }
        const templateData = processes.map(p => ({ name: p.name, clauses: Object.keys(p.matrixData) }));
        const blob = new Blob([JSON.stringify(templateData, null, 2)], { type: "application/json" });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.download = `${cleanFileName(currentStandard.name)}_Plan.json`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast("Template exported.");
    };

    const handleImportTemplate = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const content = ev.target?.result as string;
                const templateData = JSON.parse(content);
                if (!Array.isArray(templateData)) throw new Error("Invalid format");

                templateData.forEach((item: any) => {
                    if (item.name) addProcess(item.name); 
                    // Note: Clause mapping omitted due to async ID generation in this version
                });
                showToast(`Imported ${templateData.length} processes structure.`);
            } catch (err) { showToast("Import failed."); }
        };
        reader.readAsText(file);
        e.target.value = '';
    };

    if (!currentStandard) return (
        <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-2xl border border-dashed border-gray-200 dark:border-slate-800 m-4">
            <Icon name="Book" size={48} className="mb-4 opacity-20"/>
            <p className="font-bold text-slate-500">No Standard Selected</p>
            <button onClick={() => setSidebarOpen(true)} className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg text-xs font-bold flex items-center gap-2">
                <Icon name="LayoutList" size={16}/> Select Standard
            </button>
        </div>
    );

    return (
        <div className="h-full flex flex-col animate-fade-in-up gap-4 relative">

            {/* Header / Stats */}
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center justify-between shrink-0">
                <div className="flex items-center gap-6">
                    <div className="relative w-16 h-16 flex items-center justify-center shrink-0">
                        <svg className="transform -rotate-90 w-16 h-16">
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100 dark:text-slate-800" />
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" strokeDasharray={circumference} strokeDashoffset={strokeDashoffset} className="text-indigo-500 transition-all duration-1000 ease-out" strokeLinecap="round" />
                        </svg>
                        <span className="absolute text-xs font-black text-slate-700 dark:text-white">{coverageStats.percent}%</span>
                    </div>
                    <div className="flex flex-col gap-1">
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">{currentStandard.name}</h3>
                        <p className="text-xs text-slate-500">
                            <span className="font-bold text-indigo-500">{coverageStats.covered}</span> of {coverageStats.total} clauses mapped.
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64 group">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors">
                            <Icon name="Search" size={16}/>
                        </div>
                        <input 
                            ref={searchInputRef}
                            className="w-full pl-10 pr-8 py-2.5 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-800 dark:text-slate-200 placeholder-slate-400 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                            placeholder="Filter clauses..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                        {search && (
                            <button 
                                onClick={() => { setSearch(""); searchInputRef.current?.focus(); }}
                                className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-slate-400 hover:text-red-500 transition-colors"
                            >
                                <Icon name="X" size={14} />
                            </button>
                        )}
                    </div>

                    <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleImportTemplate} />
                    <button onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all hover:border-indigo-300 dark:hover:border-slate-600" title="Import Plan">
                        <Icon name="UploadCloud" size={18}/>
                    </button>
                    <button onClick={handleExportTemplate} className="p-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-slate-600 dark:text-slate-300 shadow-sm active:scale-95 transition-all hover:border-indigo-300 dark:hover:border-slate-600" title="Export Plan">
                        <Icon name="Download" size={18}/>
                    </button>
                </div>
            </div>

            {/* MATRIX CONTAINER */}
            <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 overflow-hidden shadow-sm relative flex flex-col">
                {processes.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
                        <p className="mb-4">No processes defined.</p>
                        <div className="p-4 border-2 border-dashed border-indigo-200 dark:border-indigo-900/50 rounded-xl bg-indigo-50 dark:bg-indigo-900/10 text-indigo-500">
                            Create processes in the sidebar to begin planning.
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 overflow-auto custom-scrollbar relative">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-gray-50 dark:bg-slate-950 sticky top-0 z-30 shadow-sm">
                                <tr>
                                    <th className="p-3 text-[10px] font-bold text-slate-500 uppercase tracking-wider border-b border-r border-gray-200 dark:border-slate-800 sticky left-0 bg-gray-50 dark:bg-slate-950 z-40 min-w-[300px]">
                                        Clause Reference
                                    </th>
                                    {processes.map(p => (
                                        <th key={p.id} className="p-3 text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider border-b border-gray-200 dark:border-slate-800 min-w-[120px] text-center">
                                            <div className="flex flex-col items-center gap-1">
                                                <span className="truncate max-w-[100px]" title={p.name}>{p.name}</span>
                                                <span className="text-[8px] bg-indigo-100 dark:bg-indigo-900/30 px-1.5 py-0.5 rounded text-indigo-700 dark:text-indigo-300 font-mono">
                                                    {Object.keys(p.matrixData).length}
                                                </span>
                                            </div>
                                        </th>
                                    ))}
                                </tr>
                            </thead>

                            <tbody className="divide-y divide-gray-100 dark:divide-slate-800/50">
                                {filteredGroups.map(group => {
                                    const isCollapsed = collapsedGroups.has(group.id);
                                    const groupStyle = getGroupStyle(group.id);
                                    const groupFlatList = getGroupClauses(group.clauses);

                                    return (
                                        <React.Fragment key={group.id}>
                                            {/* GROUP HEADER ROW */}
                                            <tr 
                                                className={`sticky z-20 cursor-pointer hover:brightness-95 transition-all ${groupStyle}`}
                                                onClick={() => toggleGroupCollapse(group.id)}
                                            >
                                                <td className="p-2 border-r border-black/5 dark:border-white/5 font-black text-xs uppercase tracking-widest sticky left-0 z-20 bg-inherit shadow-sm">
                                                    <div className="flex items-center justify-between">
                                                        <div className="flex items-center gap-2">
                                                            <Icon name={group.icon} size={14} className="opacity-70"/>
                                                            {group.title}
                                                        </div>
                                                        <Icon name="ChevronDown" size={14} className={`transition-transform duration-300 ${isCollapsed ? '-rotate-90' : 'rotate-0'}`}/>
                                                    </div>
                                                </td>
                                                {processes.map(p => (
                                                    <td key={`group_action_${p.id}_${group.id}`} className="p-2 text-center bg-inherit">
                                                        {!isCollapsed && (
                                                            <button 
                                                                onClick={(e) => handleGroupToggle(e, p.id, group.clauses)}
                                                                className="text-[9px] font-bold uppercase tracking-wider opacity-60 hover:opacity-100 bg-white/50 dark:bg-black/20 hover:bg-white dark:hover:bg-black/40 px-2 py-1 rounded transition-all"
                                                            >
                                                                Select Group
                                                            </button>
                                                        )}
                                                    </td>
                                                ))}
                                            </tr>

                                            {/* CLAUSE ROWS */}
                                            {!isCollapsed && groupFlatList.map(({ clause, level }) => {
                                                const isExpanded = expandedDescriptions.has(clause.id);
                                                return (
                                                    <tr key={clause.id} className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group">
                                                        <td className="p-2 border-r border-gray-100 dark:border-slate-800 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-gray-50 dark:group-hover:bg-slate-800/30 z-10 align-top">
                                                            <div className={`flex flex-col gap-1 ${level > 0 ? 'ml-4 border-l-2 border-gray-200 dark:border-slate-800 pl-2' : ''}`}>
                                                                <div className="flex items-center gap-2">
                                                                    <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300' : 'text-slate-400'}`}>
                                                                        {clause.code}
                                                                    </span>
                                                                    <span className={`text-xs truncate ${level === 0 ? 'font-bold text-slate-800 dark:text-slate-200' : 'font-medium text-slate-600 dark:text-slate-400'}`}>
                                                                        {clause.title}
                                                                    </span>
                                                                </div>

                                                                {level === 0 && (
                                                                    <div 
                                                                        onClick={() => toggleDescriptionExpand(clause.id)}
                                                                        className={`text-[10px] text-slate-500 dark:text-slate-400 mt-1 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors leading-relaxed ${isExpanded ? '' : 'line-clamp-3'}`}
                                                                        title="Click to toggle full text"
                                                                    >
                                                                        {clause.description}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </td>
                                                        {processes.map(p => {
                                                            const active = isPlanned(p.id, clause.id);
                                                            return (
                                                                <td key={`${p.id}_${clause.id}`} className="p-1 text-center border-r border-gray-50 dark:border-slate-800/50 last:border-0 relative align-middle">
                                                                    <div className="flex justify-center">
                                                                        <button
                                                                            onClick={() => handleToggle(p.id, clause.id)}
                                                                            className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-200 ${
                                                                                active 
                                                                                    ? 'bg-emerald-500 text-white shadow-sm shadow-emerald-500/40 transform scale-105' 
                                                                                    : 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-300'
                                                                            }`}
                                                                            title={active ? "Planned" : "Click to Plan"}
                                                                        >
                                                                            {active && <Icon name="CheckThick" size={14}/>}
                                                                        </button>
                                                                    </div>
                                                                </td>
                                                            );
                                                        })}
                                                    </tr>
                                                );
                                            })}
                                        </React.Fragment>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
};

export interface Clause {
    id: string;
    code: string;
    title: string;
    description: string;
    subClauses?: Clause[];
}

export interface Group {
    id: string;
    title: string;
    icon: string;
    clauses: Clause[];
}

export interface Standard {
    name: string;
    description: string;
    groups: Group[];
}

export interface StandardsData {
    [key: string]: Standard;
}

export interface AuditInfo {
    company: string;
    smo: string;
    auditor: string;
    type: string;
    // Interviewee removed from global scope, moved to AuditProcess
}

export interface PrivacySettings {
    maskCompany: boolean;
    maskSmo: boolean;
    maskPeople: boolean; // Auditee/Interiewees
    maskEmail: boolean;
    maskPhone: boolean;
    maskAddress: boolean;
    maskIP: boolean;
}

// --- NEW PROCESS ARCHITECTURE (formerly Scope) ---
export interface AuditProcess {
    id: string;
    name: string; // e.g., "Purchasing", "Production", "Management"
    evidence: string; // Raw text evidence for this process
    interviewees: string[]; // List of people interviewed for this process
    matrixData: Record<string, MatrixRow[]>; // Matrix data for this process
    evidenceTags: EvidenceTag[];
    uploadedFiles: any[]; // Store file references per process
}

export type FindingStatus = 'COMPLIANT' | 'NC_MAJOR' | 'NC_MINOR' | 'OFI' | 'N_A';
export type FindingsViewMode = 'list' | 'matrix';

export interface AnalysisResult {
    clauseId: string;
    status: FindingStatus;
    reason: string;
    suggestion: string;
    evidence: string;
    conclusion_report: string;
    crossRefs?: string[]; 
    processId?: string; // Track which process this finding belongs to
    processName?: string;
}

export interface FindingDetail {
    classification: 'N_A' | 'OFI' | 'NC_Minor' | 'NC_Major';
}

export interface ApiKeyProfile {
    id: string;
    label: string;
    key: string;
    status: 'valid' | 'invalid' | 'quota_exceeded' | 'checking' | 'unknown' | 'referrer_error';
    activeModel?: string; 
    lastResetDate?: string; 
    latency: number; 
    lastChecked: string;
}

export interface SessionSnapshot {
    id: string;
    timestamp: number;
    label: string;
    triggerType: 'AUTO_SAVE' | 'MANUAL_BACKUP'; 
    data: {
        standardKey: string;
        auditInfo: AuditInfo;
        selectedClauses: string[];
        privacySettings?: PrivacySettings;

        // Multi-Process Data Structure
        activeProcessId: string;
        processes: AuditProcess[];

        analysisResult: AnalysisResult[] | null;
        selectedFindings: Record<string, boolean>;
        finalReportText: string | null;
    };
}

